const raw = $input.item.json;
let chatId, text, isCallback, callbackData, callbackQueryId;

if (raw.callback_query) {
  chatId = raw.callback_query.from.id;
  callbackData = raw.callback_query.data;
  callbackQueryId = raw.callback_query.id;
  isCallback = true;
  text = null;
} else if (raw.message) {
  chatId = raw.message.chat.id;
  text = (raw.message.text || '').trim();
  isCallback = false;
} else {
  return [{ json: { action: 'ignore' } }];
}

const sd = $getWorkflowStaticData('global');
if (!sd.users) sd.users = {};
const uid = String(chatId);
if (!sd.users[uid]) {
  sd.users[uid] = {
    personas_default: null,
    vetos: [],
    sustituciones: {},
    estado: null,
    estado_data: null,
    lista_id: null,
    listas: {},
    pending_recipe: null
  };
}
const user = sd.users[uid];

let response = null;
let replyMarkup = null;
let answerCallbackId = callbackQueryId || null;

if (isCallback) {
  const pending = user.pending_recipe;
  if (callbackData === 'add_recipe' && pending) {
    if (!user.lista_id) user.lista_id = Math.random().toString(36).substr(2, 9);
    if (!user.listas[user.lista_id]) user.listas[user.lista_id] = { recetas: [] };
    user.listas[user.lista_id].recetas.push(pending);
    user.pending_recipe = null;
    const base = $env.WEBHOOK_URL || 'http://localhost:5678';
    const bot = $env.BOT_USERNAME || '';
    const url = `${base}/webhook/lista?id=${user.lista_id}${bot ? '&bot=' + bot : ''}`;
    response = `✅ ¡Añadido a tu lista!\n\n🛒 *Lista de la compra:*\n${url}\n\nPuedes añadir más recetas cuando quieras.`;
  } else if (callbackData === 'skip_recipe') {
    user.pending_recipe = null;
    response = 'De acuerdo 😊 Dime otra receta cuando quieras.';
  } else {
    response = 'No encontré la receta pendiente. Pide la receta de nuevo.';
  }
}
else if (text === '/start' || text === '/help') {
  response = `👋 ¡Hola! Soy tu asistente de recetas y lista de la compra.\n\n*Cómo funciona:*\n1️⃣ Dime para cuántas personas cocinas\n2️⃣ Pídeme una receta (_pollo con almendras_)\n3️⃣ Confirma si añadirla a la lista\n4️⃣ Abre el link para ir marcando en el supermercado\n\n*Comandos:*\n/sustitucion — sustituir un ingrediente\n/vetar — vetar un ingrediente\n/perfil — ver tus preferencias\n/reset — cambiar nº de personas\n/nueva — empezar lista nueva\n/eliminar [receta] — quitar receta de la lista`;
}
else if (text === '/sustitucion') {
  user.estado = 'esperando_ingrediente';
  response = '🔄 ¿Qué ingrediente NO quieres en tus recetas?';
}
else if (text && text.startsWith('/vetar')) {
  const ing = text.replace('/vetar', '').trim().toLowerCase();
  if (!ing) {
    response = 'Usa: /vetar pimiento';
  } else {
    if (!user.vetos.includes(ing)) user.vetos.push(ing);
    response = `🚫 *${ing}* vetado.\n\nVe tus preferencias con /perfil`;
  }
}
else if (text === '/perfil') {
  const v = user.vetos.length ? user.vetos.map(x => `• ${x}`).join('\n') : '• ninguno';
  const s = Object.keys(user.sustituciones).length
    ? Object.entries(user.sustituciones).map(([k, val]) => `• ${k} → ${val}`).join('\n')
    : '• ninguna';
  const lista = user.lista_id && user.listas[user.lista_id]
    ? user.listas[user.lista_id].recetas.map(r => `• ${r.receta}`).join('\n') || '• (vacía)'
    : '• (vacía)';
  response = `👤 *Tu perfil*\n\n👥 Personas: ${user.personas_default || 'no configurado'}\n\n🚫 Vetados:\n${v}\n\n🔄 Sustituciones:\n${s}\n\n📋 Lista actual:\n${lista}`;
}
else if (text === '/reset') {
  user.personas_default = null;
  response = '🔄 ¿Para cuántas personas ahora?';
}
else if (text === '/nueva') {
  user.lista_id = null;
  user.pending_recipe = null;
  response = '🗑 Lista borrada. Dime qué receta quieres:';
}
else if (text && text.startsWith('/eliminar')) {
  const nombre = text.replace('/eliminar', '').trim();
  if (!nombre) {
    response = 'Usa: /eliminar carbonara';
  } else if (!user.lista_id || !user.listas[user.lista_id]?.recetas?.length) {
    response = 'Tu lista está vacía.';
  } else {
    const lista = user.listas[user.lista_id];
    const antes = lista.recetas.length;
    lista.recetas = lista.recetas.filter(r => !r.receta.toLowerCase().includes(nombre.toLowerCase()));
    response = lista.recetas.length < antes
      ? '🗑 Receta eliminada.'
      : `No encontré esa receta. Lista: ${user.listas[user.lista_id].recetas.map(r=>r.receta).join(', ')}`;
  }
}
else if (user.estado === 'esperando_ingrediente') {
  user.estado_data = text.toLowerCase().trim();
  user.estado = 'esperando_sustituto';
  response = `¿Con qué sustituimos *${text}*?\n(escribe _nada_ para vetarlo directamente)`;
}
else if (user.estado === 'esperando_sustituto') {
  const ing = user.estado_data;
  if (text.toLowerCase() === 'nada') {
    if (!user.vetos.includes(ing)) user.vetos.push(ing);
    response = `🚫 *${ing}* vetado. Verifica con /perfil`;
  } else {
    user.sustituciones[ing] = text.toLowerCase().trim();
    response = `✅ Guardado: *${ing}* → *${text}*. Verifica con /perfil`;
  }
  user.estado = null;
  user.estado_data = null;
}
else if (!user.personas_default) {
  const num = parseInt(text);
  if (!isNaN(num) && num > 0 && num < 100) {
    user.personas_default = num;
    response = `✅ Perfecto, sois *${num} persona${num===1?'':'s'}*.\n\nDime qué receta quieres hacer 🍽`;
  } else {
    response = `👋 ¡Hola! Soy tu asistente de recetas.\n\n¿Para cuántas personas quieres las listas de la compra?`;
  }
}
else {
  const match = text.match(/\bpara\s+(\d+)\b/i);
  const personasOverride = match ? parseInt(match[1]) : null;
  const recetaLimpia = text.replace(/\bpara\s+\d+\s*personas?\b/i, '').trim();
  const personas = personasOverride || user.personas_default;
  return [{
    json: {
      action: 'recipe_request',
      chatId, uid,
      receta: recetaLimpia,
      personas,
      vetos: user.vetos,
      sustituciones: user.sustituciones
    }
  }];
}

return [{ json: { action: 'send_message', chatId, text: response, replyMarkup, answerCallbackId } }];

const ctx = $input.item.json;
const { receta, personas, vetos, sustituciones } = ctx;
const vetosStr = vetos.length ? vetos.join(', ') : 'ninguno';
const sustStr = Object.keys(sustituciones).length
  ? Object.entries(sustituciones).map(([k,v]) => `${k} → ${v}`).join(', ')
  : 'ninguna';

const systemPrompt = `Eres un chef experto. Genera recetas con ingredientes y cantidades precisas.\n\nContexto:\n- Personas: ${personas}\n- Ingredientes VETADOS: ${vetosStr}\n- Sustituciones: ${sustStr}\n\nResponde ÚNICAMENTE con JSON válido sin texto adicional:\n{\n  "nombre": "nombre receta",\n  "esVetada": false,\n  "motivoVeto": null,\n  "ingredientes": [{"nombre": "", "cantidad": 0, "unidad": "", "sustituido": false, "original": null}],\n  "preparacion": "2-3 frases"\n}\n\nReglas:\n1. Escala cantidades para ${personas} personas\n2. Si vetado es ESENCIAL: esVetada:true, explica en motivoVeto\n3. Si hay sustitución: usa el sustituto, sustituido:true, original con nombre original\n4. Vetado secundario: simplemente omítelo\n5. cantidad:null si es al gusto`;

const apiKey = $env.OPENROUTER_API_KEY || '';

const requestBodyStr = JSON.stringify({
  model: 'meta-llama/llama-3.3-70b-instruct:free',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: 'Genera la receta de: "' + receta + '"' }
  ],
  temperature: 0.2,
  max_tokens: 1500
});

return [{ json: { ...ctx, requestBodyStr, apiKey } }];

const deepseekData = $input.item.json;
const ctx = $('Preparar Prompt').item.json;
const { chatId, uid, receta, personas } = ctx;

const content = deepseekData.choices?.[0]?.message?.content || '';
let recipe;
try {
  const match = content.match(/```(?:json)?\n?([\s\S]*?)\n?```/) || [null, content];
  recipe = JSON.parse(match[1].trim());
} catch(e) {
  return [{ json: { action: 'send_message', chatId, text: `❌ No encontré la receta de _${receta}_.\n\nIntenta con un nombre más concreto.`, replyMarkup: null, answerCallbackId: null } }];
}

if (recipe.esVetada) {
  return [{ json: { action: 'send_message', chatId, text: `🚫 *${recipe.nombre}* no es posible con tus preferencias.\n\n_${recipe.motivoVeto}_\n\nPrueba con otra receta o revisa tus vetos con /perfil`, replyMarkup: null, answerCallbackId: null } }];
}

const ingredientes = (recipe.ingredientes || []).map((ing, i) => ({
  id: `ing_${Date.now()}_${i}`,
  nombre: ing.nombre,
  cantidad: ing.cantidad,
  unidad: ing.unidad || null,
  checked: false,
  sustituido: ing.sustituido || false,
  original: ing.original || null
}));

const sd = $getWorkflowStaticData('global');
if (!sd.users) sd.users = {};
if (!sd.users[uid]) sd.users[uid] = {};
sd.users[uid].pending_recipe = {
  id: `rec_${Date.now()}`,
  receta: recipe.nombre,
  personas,
  ingredientes
};

const ingLines = ingredientes.map(ing => {
  const qty = ing.cantidad != null ? `${ing.cantidad}${ing.unidad ? ' '+ing.unidad : ''}` : '';
  const sub = ing.sustituido ? ` _(↔ ${ing.original})_` : '';
  return `• ${ing.nombre}${qty ? ' — '+qty : ''}${sub}`;
}).join('\n');

const msgText = `🍽 *${recipe.nombre}* — para ${personas} persona${personas!==1?'s':''}\n\n📋 *Ingredientes:*\n${ingLines}\n\n📝 *Preparación:*\n${recipe.preparacion}\n\n¿Añado los ingredientes a la lista de la compra?`;

return [{ json: {
  action: 'send_recipe', chatId,
  text: msgText,
  replyMarkup: JSON.stringify({ inline_keyboard: [[{ text: '✅ Añadir a la lista', callback_data: 'add_recipe' }, { text: '❌ No añadir', callback_data: 'skip_recipe' }]] }),
  answerCallbackId: null
} }];

const listId = $input.item.json.query?.id || '';
const botUser = $env.BOT_USERNAME || 'tu_bot';

const html = `<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Lista de la Compra</title>
<style>
*{box-sizing:border-box;margin:0;padding:0}
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:#f0f2f5;color:#1a1a1a}
.header{background:linear-gradient(135deg,#1976D2,#42A5F5);color:white;padding:16px 20px;position:sticky;top:0;z-index:100;box-shadow:0 2px 8px rgba(0,0,0,.2)}
.header h1{font-size:20px;font-weight:700}
.header-sub{font-size:12px;opacity:.85;margin-top:3px}
.prog-bar{background:rgba(255,255,255,.3);border-radius:10px;height:4px;margin-top:8px}
.prog-fill{background:white;height:100%;border-radius:10px;transition:width .4s}
.tabs{display:flex;background:white;box-shadow:0 1px 0 #e0e0e0}
.tab{flex:1;padding:13px 0;text-align:center;cursor:pointer;font-size:14px;font-weight:500;color:#666;border-bottom:3px solid transparent;transition:all .2s}
.tab.active{color:#1976D2;border-bottom-color:#1976D2}
.content{padding:16px;max-width:640px;margin:0 auto}
.card{background:white;border-radius:14px;margin-bottom:14px;overflow:hidden;box-shadow:0 1px 4px rgba(0,0,0,.08)}
.card-header{padding:14px 16px;display:flex;align-items:center;justify-content:space-between;cursor:pointer}
.card-title{font-weight:700;font-size:16px}
.card-meta{font-size:12px;color:#888;margin-top:2px}
.card-right{display:flex;align-items:center;gap:8px}
.badge{font-size:13px;color:#1976D2;font-weight:600;background:#E3F2FD;padding:3px 8px;border-radius:12px}
.btn-del{background:none;border:none;cursor:pointer;color:#e53935;font-size:17px;padding:4px 6px;border-radius:8px}
.chevron{font-size:12px;color:#bbb;transition:transform .25s}
.collapsed .chevron{transform:rotate(-90deg)}
.collapsed .items{display:none}
.prog-card{background:#f0f0f0;height:3px}
.prog-card-fill{background:#4CAF50;height:100%;transition:width .4s}
.items{border-top:1px solid #f5f5f5}
.item{display:flex;align-items:center;padding:11px 16px;border-bottom:1px solid #fafafa;gap:12px}
.item:hover{background:#fafafa}
.item input{width:20px;height:20px;cursor:pointer;accent-color:#1976D2;flex-shrink:0}
.iname{flex:1;font-size:15px;transition:all .2s}
.iname.done{text-decoration:line-through;color:#bbb}
.isub{font-size:11px;color:#FF7043;margin-top:1px}
.iqty{font-size:13px;color:#999;white-space:nowrap;font-weight:500}
.sec-label{font-size:11px;text-transform:uppercase;letter-spacing:.8px;font-weight:700;color:#999;padding:16px 4px 8px}
.empty{text-align:center;padding:80px 24px}
.empty-icon{font-size:64px;margin-bottom:16px}
.empty-title{font-size:18px;font-weight:600;color:#444;margin-bottom:8px}
.add-btn{display:flex;align-items:center;justify-content:center;gap:8px;background:#1976D2;color:white;border:none;padding:15px 24px;border-radius:28px;font-size:15px;font-weight:600;cursor:pointer;width:100%;margin-top:8px;margin-bottom:24px;box-shadow:0 3px 10px rgba(25,118,210,.4)}
.toast{position:fixed;bottom:24px;left:50%;transform:translateX(-50%);background:#323232;color:white;padding:10px 22px;border-radius:22px;font-size:14px;opacity:0;pointer-events:none;transition:opacity .25s;z-index:999;white-space:nowrap}
.toast.on{opacity:1}
.spin{width:36px;height:36px;border:3px solid #e0e0e0;border-top-color:#1976D2;border-radius:50%;animation:s .8s linear infinite;margin:0 auto 16px}
@keyframes s{to{transform:rotate(360deg)}}
.loading{text-align:center;padding:60px;color:#aaa}
</style>
</head>
<body>
<div class="header">
  <h1>🛒 Lista de la Compra</h1>
  <div class="header-sub" id="hsub">Cargando...</div>
  <div class="prog-bar"><div class="prog-fill" id="hprog" style="width:0%"></div></div>
</div>
<div class="tabs">
  <div class="tab active" onclick="tab('r')" id="tr">🍽 Por receta</div>
  <div class="tab" onclick="tab('c')" id="tc">📋 Consolidada</div>
</div>
<div id="vr" class="content"></div>
<div id="vc" class="content" style="display:none"></div>
<div class="toast" id="toast"></div>
<script>
const P=new URLSearchParams(location.search),lid=P.get('id'),BOT='${botUser}',API=location.origin;
let data={recetas:[]},activeTab='r';
async function load(){
  if(!lid){err('Sin ID de lista');return;}
  try{
    const r=await fetch(API+'/webhook/lista-data?id='+lid);
    if(!r.ok)throw new Error();
    data=await r.json();
    render();
  }catch(e){err('No se pudo cargar la lista. ¿Está n8n activo?');}
}
function err(m){document.getElementById('vr').innerHTML='<div class="empty"><div class="empty-icon">❌</div><div class="empty-title">'+m+'</div></div>';}
function tab(t){
  activeTab=t;
  document.getElementById('tr').classList.toggle('active',t==='r');
  document.getElementById('tc').classList.toggle('active',t==='c');
  document.getElementById('vr').style.display=t==='r'?'':'none';
  document.getElementById('vc').style.display=t==='c'?'':'none';
}
function esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function fqty(i){if(!i.cantidad&&!i.unidad)return '';const q=i.cantidad!=null?(Number.isInteger(i.cantidad)?i.cantidad:parseFloat(i.cantidad.toFixed(1))):'';return (q+' '+(i.unidad||'')).trim();}
function render(){
  const rs=data.recetas||[];
  const tot=rs.reduce((s,r)=>s+r.ingredientes.length,0);
  const don=rs.reduce((s,r)=>s+r.ingredientes.filter(i=>i.checked).length,0);
  const pct=tot>0?Math.round(don/tot*100):0;
  document.getElementById('hsub').textContent=rs.length+' receta'+(rs.length!==1?'s':'')+' · '+tot+' ingrediente'+(tot!==1?'s':'')+(tot>0?' · '+don+'/'+tot+' en carro':'');
  document.getElementById('hprog').style.width=pct+'%';
  renderR(rs);renderC(rs);
}
function renderR(rs){
  const el=document.getElementById('vr');
  if(!rs.length){el.innerHTML='<div class="empty"><div class="empty-icon">🍽</div><div class="empty-title">Lista vacía</div><p style="color:#888;margin-top:8px">Pídele una receta al bot para empezar</p></div>';return;}
  el.innerHTML=rs.map(rec=>{
    const tot=rec.ingredientes.length,chk=rec.ingredientes.filter(i=>i.checked).length,pct=tot>0?chk/tot*100:0;
    return '<div class="card" id="card-'+rec.id+'">'+
      '<div class="card-header" onclick="tog(\''+rec.id+'\')">'+'<div><div class="card-title">'+esc(rec.receta)+'</div><div class="card-meta">Para '+rec.personas+' persona'+(rec.personas!==1?'s':'')+'</div></div>'+'<div class="card-right"><span class="badge">'+chk+'/'+tot+'</span><button class="btn-del" onclick="event.stopPropagation();del(\''+rec.id+'\',\''+esc(rec.receta)+'\')" title="Eliminar">🗑</button><span class="chevron">▼</span></div></div>'+
      '<div class="prog-card"><div class="prog-card-fill" style="width:'+pct+'%"></div></div>'+
      '<div class="items">'+rec.ingredientes.map(ing=>'<div class="item"><input type="checkbox" id="c-'+ing.id+'" '+(ing.checked?'checked':'')+' onchange="toggleItem(\''+rec.id+'\',\''+ing.id+'\',this.checked)"><label for="c-'+ing.id+'" style="flex:1;cursor:pointer"><div class="iname'+(ing.checked?' done':'')+'">'+esc(ing.nombre)+'</div>'+(ing.sustituido?'<div class="isub">✱ sustituido de '+esc(ing.original)+'</div>':'')+'</label><span class="iqty">'+fqty(ing)+'</span></div>').join('')+'</div></div>';
  }).join('')+'<button class="add-btn" onclick="window.open(\'https://t.me/'+BOT+'\',\'_blank\')">+ Añadir otra receta</button>';
}
function renderC(rs){
  const el=document.getElementById('vc');
  if(!rs.length){el.innerHTML='<div class="empty"><div class="empty-icon">📋</div><div class="empty-title">Sin ingredientes</div></div>';return;}
  const map={};
  rs.forEach(rec=>rec.ingredientes.forEach(ing=>{
    const key=ing.nombre.trim().toLowerCase();
    if(map[key]){map[key].recetas.push(rec.receta);if(ing.unidad&&map[key].unidad===ing.unidad&&ing.cantidad!=null)map[key].cantidad=(parseFloat(map[key].cantidad)||0)+parseFloat(ing.cantidad);if(!ing.checked)map[key].checked=false;map[key].refs.push({rId:rec.id,iId:ing.id});}
    else map[key]={nombre:ing.nombre,cantidad:ing.cantidad,unidad:ing.unidad,checked:ing.checked,recetas:[rec.receta],refs:[{rId:rec.id,iId:ing.id}]};
  }));
  const items=Object.values(map),pend=items.filter(i=>!i.checked),done=items.filter(i=>i.checked);
  let h='';
  if(pend.length)h+='<div class="card"><div class="items">'+pend.map(i=>cItem(i)).join('')+'</div></div>';
  if(done.length)h+='<div class="sec-label">✓ Ya en el carro</div><div class="card" style="opacity:.6"><div class="items">'+done.map(i=>cItem(i)).join('')+'</div></div>';
  el.innerHTML=h+'<button class="add-btn" onclick="window.open(\'https://t.me/'+BOT+'\',\'_blank\')">+ Añadir otra receta</button>';
}
function cItem(ing){
  const key=ing.nombre.trim().toLowerCase();
  return '<div class="item"><input type="checkbox" id="cons-'+key+'" '+(ing.checked?'checked':'')+' onchange="toggleCons(\''+key+'\',this.checked,'+JSON.stringify(ing.refs)+')"><label for="cons-'+key+'" style="flex:1;cursor:pointer"><div class="iname'+(ing.checked?' done':'')+'">'+esc(ing.nombre)+'</div><div class="isub" style="color:#999">'+ing.recetas.join(' · ')+'</div></label><span class="iqty">'+fqty(ing)+'</span></div>';
}
function tog(id){document.getElementById('card-'+id)?.classList.toggle('collapsed');}
async function toggleItem(rId,iId,checked){
  const rec=data.recetas.find(r=>r.id===rId);if(rec){const i=rec.ingredientes.find(i=>i.id===iId);if(i)i.checked=checked;}
  render();toast(checked?'✓ En el carro':'Quitado');
  await fetch(API+'/webhook/lista-toggle',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({listId:lid,recipeId:rId,ingId:iId,checked})}).catch(()=>{});
}
async function toggleCons(key,checked,refs){
  refs.forEach(({rId,iId})=>{const rec=data.recetas.find(r=>r.id===rId);if(rec){const i=rec.ingredientes.find(i=>i.id===iId);if(i)i.checked=checked;}});
  render();toast(checked?'✓ En el carro':'Quitado');
  await Promise.allSettled(refs.map(({rId,iId})=>fetch(API+'/webhook/lista-toggle',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({listId:lid,recipeId:rId,ingId:iId,checked})}))).catch(()=>{});
}
async function del(rId,nombre){
  if(!confirm('¿Eliminar "'+nombre+'" de la lista?'))return;
  data.recetas=data.recetas.filter(r=>r.id!==rId);render();toast('Receta eliminada');
  await fetch(API+'/webhook/lista-eliminar',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({listId:lid,recipeId:rId})}).catch(()=>{});
}
